"_pillarItemTitle_xv413_629",te="_pillarItemSubtitle_xv413_643",ne="_pillarItemQuote_xv413_661",le="_sectionIntro_xv413_767",oe="_pillarsIntro_xv413_769",me="_sectionIntroCopy_xv413_779",ce="_pillarsDescription_xv413_781",ue="_programAnchor_xv413_815",de="_programActionRow_xv413_971",ge="_programExploreLink_xv413_987",be="_pillarsEyebrow_xv413_1057",he="_pillarsHeading_xv413_1067",pe="_impactHeading_xv413_1069",Ne="_pillarsFooter_xv413_1085",ve="_pillarsLink_xv413_1095",fe="_ctaAccent_xv413_1189",xe="_ctaCopy_xv413_1197",_e="_ctaActions_xv413_1213",ye="_ctaPrimary_xv413_1227",Ee="_ctaSecondary_xv413_1237",r={container:U,realityBanner:w,bannerStats:S,bannerStatItem:I,ctaEditorial:k,programsSection:L,programsWrapper:T,programCard:H,programCardInner:B,programNumber:M,programBody:O,programTitle:W,programTagline:$,programSummary:F,programStatRow:q,programStatItem:Y,programStatValue:z,programStatLabel:K,programDetail:Q,programDetailLine:J,programReadMore:X,pillarsSection:Z,pillarsWrapper:ee,pillarsGrid:se,pillarItem:re,pillarItemNumber:ae,pillarItemTitle:ie,pillarItemSubtitle:te,pillarItemQuote:ne,sectionIntro:le,pillarsIntro:oe,sectionIntroCopy:me,pillarsDescription:ce,programAnchor:ue,programActionRow:de,programExploreLink:ge,pillarsEyebrow:be,pillarsHeading:he,impactHeading:pe,pillarsFooter:Ne,pillarsLink:ve,ctaAccent:fe,ctaCopy:xe,ctaActions:_e,ctaPrimary:ye,ctaSecondary:Ee},Ce=[{id:"rise-rooms",number:"01",title:"The Rise Room Initiative",tagline:"A sanctuary. A lifeline. A place where silence can finally break.",summary:"A Rise Room is a dedicated safe space within a partner school where girls come to heal, speak freely, and find support. There are no desks, no chalkboards, no pressure to perform — instead cushions, soft lighting, and a circle of chairs where everyone sits as equals.",stats:[{value:"15",label:"Rise Rooms established"},{value:"800+",label:"Girls reached"},{value:"42",label:"Peer counsellors trained"},{value:"92%",label:"School retention rate"}],detail:["In Ibanda District, girls carry weights no child should carry: trauma from losing parents, grief from watching siblings go hungry, shame from abuse they did not cause, and the anxiety of wondering if they will be the next to drop out or be married off. They carry it all in silence.","Rise Rooms exist to say: You are not alone. Your feelings matter. You deserve to heal.","What happens inside a Rise Room:","• Individual Counselling — one-on-one sessions with trained counsellors in trauma-informed care","• Group Circles — girls discover they are not alone in their struggles","• Peer Support — older girls trained to listen, validate, and guide younger peers","• Art Therapy — drawing, writing, and creating to express what words cannot hold","• Quiet Space — sometimes a girl simply needs to rest","Before Rise Rooms, 85% of girls reported feeling completely alone in their struggles. After, 75% know they are not alone. School attendance rose from 62% to 92%."],href:"/programs/rise-rooms"},{id:"academic-rescue",number:"02",title:"Academic Rescue Program",tagline:"No girl should leave school because the world made it too hard to stay.",summary:"In Uganda, 4 in 10 girls drop out before completing secondary school — not because they lack intelligence or determination, but because the world puts obstacle after obstacle in their path. The Academic Rescue Program exists to remove those obstacles, one girl at a time.",stats:[{value:"92%",label:"Stay in school (vs 60% nationally)"},{value:"4 in 10",label:"Girls drop out nationally — we fight this"},{value:"100%",label:"Exam fees covered"},{value:"0",label:"Girls sent home for worn uniforms"}],detail:["Girls drop out because uniforms wear out, exercise books run out, sanitary pads are a luxury, exam fees come due with no money to pay, or they are needed at home to care for siblings. These are not failures of effort — they are failures of circumstance.","1. Uniforms & Shoes — A girl in a torn uniform is sent home. We provide complete uniforms and shoes so every girl walks into school with dignity.","2. Scholastic Materials — Exercise books, pens, pencils, geometry sets, and textbooks so girls can focus on learning, not on what they lack.","3. Sanitary Pads — 1 in 10 girls misses school during her period. We provide reusable pad kits so no girl ever misses class again.","4. Exam Fees — We cover national exam fees so no girl is barred from sitting for her future.","5. Emergency Support — When a crisis hits — a parent dies, a harvest fails, a family is displaced — we provide immediate support to keep the girl in school.","6. Tutoring & Remedial Classes — After-school tutoring and exam preparation for girls who have fallen behind due to absences or trauma.","92% of girls in our programme stay in school — compared to 60% nationally."],href:"/programs/academic-rescue"},{id:"leadership-life-skills",number:"03",title:"Leadership & Life Skills Program",tagline:"A girl who can provide for herself will never be trapped. A girl who can lead will change the world.",summary:"We equip girls with practical skills they can use immediately — for themselves, for their families, and for income generation. Then we develop them into leaders who transform their communities through the Rise Enterprise Group model.",stats:[{value:"95%",label:"Can make reusable pads"},{value:"85%",label:"Can make liquid soap"},{value:"30%",label:"Have started small businesses"},{value:"15K–50K",label:"UGX earned monthly per girl"}],detail:["We do not give girls fish. We teach them to fish — and to make their own nets.","Life skills taught include Reusable Pad Making (never miss school again), Liquid Soap Making (hygiene for the family and income from selling), Vaseline & Body Lotion production, Tailoring & Repairs (mend uniforms, make clothes, earn income), Notebook Making, Financial Literacy, and Entrepreneurship.","The Enterprise Group Model: Girls form small groups of 5–10 members to buy materials in bulk, produce together, sell at markets and schools, save money collectively (village savings model), and support each other through challenges.",'Example: The "Rise Sisters" group makes soap, lotion, and pads together. Each girl earns 10,000–20,000 UGX per month — enough for school supplies and to help her family.',"Leadership Development: Girls move through five stages — Discovery, Planning, Action, Reflection, and Mentoring. Every girl who completes the programme designs a community project and pledges to mentor at least one girl each year.",'The Alumni Promise: "I will reach back. I will mentor at least one girl each year. I will prove that her beginning does not define her becoming."'],href:"/programs/leadership-life-skills"},{id:"health-wellness",number:"04",title:"Health & Wellness Program",tagline:"A healthy girl is a rising girl.",summary:"A girl cannot learn, lead, or dream if her body is failing her. Health is not a luxury — it is the foundation upon which everything else is built. We address the whole girl: her physical health, menstrual health, nutrition, and access to healthcare.",stats:[{value:"1 in 10",label:"Girls miss school due to periods — we end this"},{value:"6–12mo",label:"Each reusable pad lasts"},{value:"100%",label:"Girls receive SRHR education"},{value:"0",label:"Girls left without a healthcare referral"}],detail:["Girls in Ibanda District face daily health challenges that keep them from school and from thriving. Mental distress affects physical health; physical illness worsens mental distress. We address both, always, together.","1. Menstrual Health Management — Every girl learns to make her own reusable pads. One pad lasts 6–12 months. No more missing school, no more shame. We also provide education to break the silence around menstruation.","2. Nutrition & Food Security — Emergency food support for girls whose families cannot feed them. Nutrition education on balanced meals on a budget. Support for small vegetable gardens at home.","3. Sexual & Reproductive Health Education — Age-appropriate education on puberty, consent, healthy relationships, HIV/STI prevention, dangers of early pregnancy, contraception, and where to access services.","4. Access to Healthcare — We connect girls to local health centres, HIV testing and counselling, family planning services, antenatal care for pregnant girls, and emergency medical support.","5. Physical Wellness — Sports, recreation, basic exercise, understanding the connection between physical and mental health, and rest education.","6. Mental Health Integration — Health & Wellness works hand-in-hand with our Rise Rooms pillar. Holistic healing. Whole girls. Complete wellness."],href:"/programs/health-wellness"},{id:"future-pathways",number:"05",title:"Future Pathways Program",tagline:"A girl with a vision for her future will never settle for less.",summary:"Many girls in Ibanda District have never met a female doctor, lawyer, or engineer. You cannot become what you cannot imagine. Future Pathways bridges the gap between dreaming and doing — equipping every girl with a concrete plan and the support to reach it.",stats:[{value:"200+",label:"Girls in career exposure events"},{value:"50+",label:"Professional mentors connected"},{value:"15",label:"Girls in university or vocational training"},{value:"40%",label:"Alumni actively mentoring"}],detail:["You cannot become what you cannot imagine. Girls in Ibanda rarely see female doctors, lawyers, engineers, or business owners. The Future Pathways Programme bridges that gap.","1. Career Exposure — Career Days where professionals visit girls to share their journeys. Exposure tours to universities and businesses. Job shadowing: selected girls spend a day with a professional, ask questions, and build networks.","2. Mentorship — Professional women in careers girls dream of, near-peer mentors who recently completed the programme, and lifetime mentoring relationships.","3. University & Vocational Preparation — Subject guidance, application support (personal statements and interviews), scholarship connections, and intensive exam preparation.","4. Vocational Training Pathways — For girls who prefer hands-on careers: Tailoring & Fashion Design, Catering & Hotel Management, Hairdressing & Cosmetology, Agriculture, Construction & Carpentry, or Information Technology.",'5. The "My Rise Plan" — Every girl creates a personalised roadmap: Where do I want to be in 5 years? What education and skills do I need? What steps will I take, and when? Who can help me?','6. Rise Alumni Network — Graduates join a lifelong community, mentor current girls, access job and training opportunities, and carry the motto: "Rise. Then reach back. Always."'],href:"/programs/future-pathways"},{id:"rise-brothers",number:"06",title:"Rise Brothers",tagline:"Strong boys support strong girls. Together, we rise.",summary:"Rise Brothers is the boys-focused allyship programme at African Girl Rise. It teaches boys to understand what girls face, manage their own emotions in healthy ways, and become protectors, peers, and advocates who help break harmful cycles early.",stats:[{value:"Weekly",label:"Mental health circles"},{value:"Bi-weekly",label:"Allyship workshops"},{value:"Monthly",label:"Joint sessions with girls"},{value:"Annual",label:"Rise Brothers Summit"}],detail:["We cannot empower girls in isolation. Boys grow into the fathers, husbands, teachers, police officers, and judges who shape the systems girls must navigate later.","Rise Brothers teaches emotional literacy, gender equality, consent, menstrual health understanding, peer accountability, and practical life skills that build self-sufficiency.","Boys learn to speak about their feelings without shame, interrupt bullying and abuse, help with pad-making workshops, and reject the idea that care work is only for women.","Graduates leave with a certificate, mental health first aid knowledge, practical skills, and a lifelong commitment to stand beside girls as allies."],href:"/programs/rise-brothers"}];f